import React, { useState } from 'react';
import api from '../../services/api';
import { FiEdit2, FiTrash2, FiPlus } from 'react-icons/fi';
import { useToast } from '../../context/ToastContext';
import { useConfirm } from '../../context/ConfirmContext';
import useApi from '../../hooks/useApi';
import useDebounce from '../../hooks/useDebounce';
import validation from '../../utils/validation';
import DebouncedInput from '../../components/common/DebouncedInput';
import { SkeletonTable } from '../../components/common/Skeleton';
import FormField from '../../components/common/FormField';

const userRules = (isEdit) => ({
  username: validation.compose(validation.required('Username is required'), validation.minLength(3, 'Minimum 3 characters')),
  password: isEdit ? () => null : validation.required('Password is required'),
});

const AdminUsers = () => {
  const [search, setSearch] = useState('');
  const debouncedSearch = useDebounce(search);
  const [showModal, setShowModal] = useState(false);
  const [editUser, setEditUser] = useState(null);
  const [form, setForm] = useState({ username: '', password: '', role: 'ess', status: true });
  const [touched, setTouched] = useState({});
  const toast = useToast();
  const confirm = useConfirm();

  const fetchUsers = () => api.get('/admin/users');
  const { data: users, loading, execute: loadUsers } = useApi(fetchUsers, { immediate: true, showToast: false });

  const filteredUsers = (users || []).filter(u =>
    !debouncedSearch || u.username.toLowerCase().includes(debouncedSearch.toLowerCase())
  );

  const formErrors = validation.validate(form, userRules(!!editUser));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setTouched({ username: true, password: true });
    if (!formErrors.valid) return;
    try {
      if (editUser) {
        const payload = { ...form };
        if (!payload.password) delete payload.password;
        await api.put(`/admin/users/${editUser._id}`, payload);
        toast.success('User updated successfully');
      } else {
        await api.post('/admin/users', form);
        toast.success('User created successfully');
      }
      setShowModal(false);
      setEditUser(null);
      setForm({ username: '', password: '', role: 'ess', status: true });
      setTouched({});
      loadUsers();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Operation failed');
    }
  };

  const handleEdit = (user) => {
    setEditUser(user);
    setForm({ username: user.username, password: '', role: user.role, status: user.status });
    setTouched({});
    setShowModal(true);
  };

  const handleDelete = async (id, username) => {
    const confirmed = await confirm(`Delete user "${username}"? This action cannot be undone.`, 'Delete User');
    if (!confirmed) return;
    try {
      await api.delete(`/admin/users/${id}`);
      toast.success('User deleted successfully');
      loadUsers();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Delete failed');
    }
  };

  return (
    <div>
      <div className="toolbar">
        <DebouncedInput value={search} onChange={setSearch} placeholder="Search users..." />
        <div className="toolbar-right">
          <button className="btn btn-primary" onClick={() => { setEditUser(null); setForm({ username: '', password: '', role: 'ess', status: true }); setTouched({}); setShowModal(true); }}><FiPlus /> Add User</button>
        </div>
      </div>
      <div className="card">
        <div className="card-header"><h3>System Users</h3><span style={{ color: '#999', fontSize: 13 }}>{filteredUsers.length} records</span></div>
        <div className="card-body">
          <div className="table-container">
            <table>
              <thead><tr><th>Username</th><th>Role</th><th>Status</th><th>Employee</th><th>Last Login</th><th>Actions</th></tr></thead>
              <tbody>
                {loading ? <SkeletonTable rows={5} cols={6} /> : (
                  filteredUsers.map(u => (
                    <tr key={u._id}>
                      <td><strong>{u.username}</strong></td>
                      <td><span className="status-badge" style={{ background: u.role === 'admin' ? '#fff3e0' : '#e3f2fd', color: u.role === 'admin' ? '#e65100' : '#1565c0' }}>{u.role}</span></td>
                      <td><span className={`status-badge ${u.status ? 'status-approved' : 'status-rejected'}`}>{u.status ? 'Enabled' : 'Disabled'}</span></td>
                      <td>{u.employeeId?.fullName || '-'}</td>
                      <td>{u.lastLogin ? new Date(u.lastLogin).toLocaleString() : 'Never'}</td>
                      <td>
                        <button className="action-btn" onClick={() => handleEdit(u)} title="Edit"><FiEdit2 /></button>
                        <button className="action-btn" onClick={() => handleDelete(u._id, u.username)} title="Delete"><FiTrash2 /></button>
                      </td>
                    </tr>
                  ))
                )}
                {!loading && filteredUsers.length === 0 && <tr><td colSpan={6} style={{ textAlign: 'center', padding: 24, color: '#999' }}>No users found</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      </div>
      {showModal && (
        <div className="modal-backdrop" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header"><h3>{editUser ? 'Edit User' : 'Add User'}</h3><button className="close-btn" onClick={() => setShowModal(false)}>&times;</button></div>
            <form onSubmit={handleSubmit}>
              <div className="modal-body">
                <FormField label="Username" name="username" error={formErrors.errors.username} touched={touched.username} required>
                  <input value={form.username} onChange={e => { setForm({...form, username: e.target.value}); setTouched({...touched, username: true}); }} />
                </FormField>
                <FormField label={`Password ${editUser ? '(leave blank to keep)' : ''}`} name="password" error={formErrors.errors.password} touched={touched.password} required={!editUser}>
                  <input type="password" value={form.password} onChange={e => { setForm({...form, password: e.target.value}); setTouched({...touched, password: true}); }} />
                </FormField>
                <div className="form-group"><label>Role</label>
                  <select value={form.role} onChange={e => setForm({...form, role: e.target.value})}>
                    <option value="admin">Admin</option><option value="ess">ESS</option><option value="supervisor">Supervisor</option>
                  </select>
                </div>
                <div className="form-group"><label><input type="checkbox" checked={form.status} onChange={e => setForm({...form, status: e.target.checked})} /> Active</label></div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-outline" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary">{editUser ? 'Update' : 'Save'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminUsers;
